function processClaim(
  policy: { items: any[]; insuranceSum: number; remainingCap: number },
  incident: any,
): { payout: number; remainingCap: number } {
  let totalPayout = 0;
  for (const damage of incident.damages) {
    const matchedItem = policy.items.find((item: any) => item.type === damage.itemType);
    const reimbursementRate = matchedItem && matchedItem.enchantment >= CLAIM_ENCHANTMENT_THRESHOLD ? CLAIM_ENCHANTMENT_REIMBURSEMENT_RATE : 1;
    const reimbursement = damage.amount * reimbursementRate - DEDUCTIBLE;
    totalPayout += reimbursement;
  }
  policy.remainingCap -= totalPayout;
  return { payout: totalPayout, remainingCap: policy.remainingCap };
}

